export enum Mode {
  SINGLE = 'SINGLE',
  BATCH = 'BATCH'
}

export interface AuditItem {
  change: string;
  reason: string;
  factualConfirmation: string;
}

export interface RefinedData {
  optimizedTitle: string;
  shortSummary: string;
  rewrittenDescription: string;
  seoKeywords: string[];
  auditTrail: AuditItem[];
  operationalAlerts?: string;
  targetAudience?: string;
  missingInfo?: string[];
}

export interface BatchItem {
  id: string;
  originalText: string;
  status: 'pending' | 'processing' | 'completed' | 'error';
  result?: RefinedData;
  errorMsg?: string;
}

export interface GroundingResult {
  source: 'maps' | 'search';
  data: string;
  uris?: { uri: string; title: string }[];
}

import { GoogleGenAI, Type, Schema } from "@google/genai";

// Use specific models as per guidelines
const MODEL_REFINER = "gemini-3-pro-preview"; 
const MODEL_GROUNDING = "gemini-2.5-flash";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const refinerSchema: Schema = {
  type: Type.OBJECT,
  properties: {
    optimizedTitle: { type: Type.STRING, description: "A catchy, SEO-friendly title (Destination + Type + Difference)." },
    shortSummary: { type: Type.STRING, description: "A one-sentence inviting summary with immediate value proposition." },
    rewrittenDescription: { type: Type.STRING, description: "The improved description using Markdown (H2 ##, H3 ###, bullets). Must follow V2 structure." },
    seoKeywords: { 
      type: Type.ARRAY, 
      items: { type: Type.STRING },
      description: "List of 5-8 natural keywords." 
    },
    operationalAlerts: { type: Type.STRING, description: "Section 'Bom saber antes de reservar' if sensitive activities are involved. Leave empty if none." },
    targetAudience: { type: Type.STRING, description: "Indicates who the experience is ideal for." },
    missingInfo: { 
      type: Type.ARRAY, 
      items: { type: Type.STRING },
      description: "List of critical missing data like duration or accessibility. Use this ONLY if details are truly missing." 
    },
    auditTrail: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          change: { type: Type.STRING, description: "What specific part was changed." },
          reason: { type: Type.STRING, description: "Why it was changed." },
          factualConfirmation: { type: Type.STRING, description: "Confirmation that no facts were altered." }
        },
        required: ["change", "reason", "factualConfirmation"]
      }
    }
  },
  required: ["optimizedTitle", "shortSummary", "rewrittenDescription", "seoKeywords", "targetAudience", "auditTrail"]
};

export const refineProductText = async (originalText: string) => {
  try {
    const response = await ai.models.generateContent({
      model: MODEL_REFINER,
      contents: `
        You are the "iFriend Experience Refiner v2", a professional agent transforming raw tourism descriptions for the iFriend platform.

        OBJECTIVE: Generate clear, safe, scannable, and conversion-oriented descriptions.

        MANDATORY RULES:
        1. **LANGUAGE FIDELITY**: AUTO-DETECT language. Output MUST be in the SAME LANGUAGE as Input (PT -> PT, ES -> ES, EN -> EN).
        2. **STRUCTURE**: 
           - Title: Destination + Type + Difference.
           - Hook: Immediate value proposition.
           - "O que esperar" / "Destaques".
           - "Detalhes" / "Informações importantes".
        3. **FORMAT**: Markdown (H2, H3, lists). Short sentences. No flowery language. No exaggeration.
        4. **FIDELITY**: NEVER invent facts (duration, logistics, services). NEVER infer unstated info.
        5. **MISSING INFO**: If duration, accessibility, or logistics are missing, populate the 'missingInfo' field and be objective.
        6. **ALERTS**: If it involves flights, boats, long tours, or physical intensity, create the "Good to know" alert based ONLY on provided text.
        7. **SEO**: Natural keywords, priority for long-tail.

        Input Text:
        "${originalText}"
      `,
      config: {
        responseMimeType: "application/json",
        responseSchema: refinerSchema,
        temperature: 0.2, 
      }
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI");

    return JSON.parse(text);
  } catch (error) {
    console.error("Refinement Error:", error);
    throw error;
  }
};

export const verifyLocationWithMaps = async (query: string) => {
  try {
    const response = await ai.models.generateContent({
      model: MODEL_GROUNDING,
      contents: `Verify the existence and basic details of this location: ${query}. Respond in the same language as the query.`,
      config: {
        tools: [{ googleMaps: {} }],
      }
    });

    const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
    const uris = chunks?.map((c: any) => ({
      uri: c.maps?.uri || '',
      title: c.maps?.title || 'View on Maps'
    })).filter((u: any) => u.uri) || [];

    return {
      text: response.text || "Location verification not available.",
      uris
    };
  } catch (error) {
    console.error("Maps Error:", error);
    return { text: "Could not verify location at this time.", uris: [] };
  }
};

export const checkFactsWithSearch = async (query: string) => {
  try {
    const response = await ai.models.generateContent({
      model: MODEL_GROUNDING,
      contents: `Fact check this detail: ${query}. Respond in the same language as the query.`,
      config: {
        tools: [{ googleSearch: {} }],
      }
    });

    const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
    const uris = chunks?.map((c: any) => ({
      uri: c.web?.uri || '',
      title: c.web?.title || 'Source'
    })).filter((u: any) => u.uri) || [];

    return {
      text: response.text || "Fact check not available.",
      uris
    };
  } catch (error) {
    console.error("Search Error:", error);
    return { text: "Could not perform search fact check.", uris: [] };
  }
};

import React, { useState } from 'react';
import { RefinedData, GroundingResult } from '../types';
import { verifyLocationWithMaps, checkFactsWithSearch } from '../services/geminiService';

interface ResultCardProps {
  originalText: string;
  data: RefinedData;
}

export const ResultCard: React.FC<ResultCardProps> = ({ originalText, data }) => {
  const [activeTab, setActiveTab] = useState<'refined' | 'audit' | 'original'>('refined');
  const [groundingResult, setGroundingResult] = useState<GroundingResult | null>(null);
  const [loadingGrounding, setLoadingGrounding] = useState(false);

  const handleVerifyLocation = async () => {
    setLoadingGrounding(true);
    setGroundingResult(null);
    try {
      const query = data.optimizedTitle; 
      const result = await verifyLocationWithMaps(query);
      setGroundingResult({ source: 'maps', data: result.text, uris: result.uris });
    } finally {
      setLoadingGrounding(false);
    }
  };

  const handleFactCheck = async () => {
    setLoadingGrounding(true);
    setGroundingResult(null);
    try {
        const query = data.shortSummary;
        const result = await checkFactsWithSearch(query);
        setGroundingResult({ source: 'search', data: result.text, uris: result.uris });
    } finally {
        setLoadingGrounding(false);
    }
  };

  return (
    <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden flex flex-col h-full">
      {/* Missing Info Warning */}
      {data.missingInfo && data.missingInfo.length > 0 && (
        <div className="bg-amber-50 border-b border-amber-100 p-3 flex gap-3 items-center">
          <div className="flex-shrink-0 text-amber-500">
            <svg className="w-5 h-5" fill="currentColor" viewBox="0 0 20 20">
              <path fillRule="evenodd" d="M8.257 3.099c.765-1.36 2.722-1.36 3.486 0l5.58 9.92c.75 1.334-.213 2.98-1.742 2.98H4.42c-1.53 0-2.493-1.646-1.743-2.98l5.58-9.92zM11 13a1 1 0 11-2 0 1 1 0 012 0zm-1-8a1 1 0 00-1 1v3a1 1 0 002 0V6a1 1 0 00-1-1z" clipRule="evenodd" />
            </svg>
          </div>
          <div>
            <p className="text-xs font-bold text-amber-800 uppercase tracking-tight">Missing Critical Information</p>
            <p className="text-xs text-amber-700">The following data was missing in the input: {data.missingInfo.join(', ')}</p>
          </div>
        </div>
      )}

      {/* Header */}
      <div className="bg-slate-50 px-6 py-4 border-b border-slate-100 flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <div className="flex items-center gap-2 mb-1">
             <h3 className="text-lg font-bold text-slate-800">{data.optimizedTitle}</h3>
             {data.targetAudience && (
               <span className="text-[10px] font-bold px-2 py-0.5 bg-indigo-50 text-indigo-600 border border-indigo-100 rounded-full uppercase">
                 {data.targetAudience}
               </span>
             )}
          </div>
          <p className="text-sm text-slate-500">{data.shortSummary}</p>
        </div>
        <div className="flex gap-2">
          <button
            onClick={handleVerifyLocation}
            disabled={loadingGrounding}
            className="text-xs font-medium px-3 py-1.5 bg-blue-50 text-blue-600 rounded-full hover:bg-blue-100 transition flex items-center gap-1"
          >
            {loadingGrounding ? 'Checking...' : 'Verify Location'}
          </button>
          <button
            onClick={handleFactCheck}
            disabled={loadingGrounding}
            className="text-xs font-medium px-3 py-1.5 bg-teal-50 text-teal-600 rounded-full hover:bg-teal-100 transition flex items-center gap-1"
          >
             {loadingGrounding ? 'Checking...' : 'Search Grounding'}
          </button>
        </div>
      </div>

      {/* Grounding Result Area */}
      {groundingResult && (
        <div className="bg-slate-50 border-b border-slate-200 p-4 animate-fade-in">
           <div className="flex items-start gap-3">
              <div className={`mt-1 w-2 h-2 rounded-full ${groundingResult.source === 'maps' ? 'bg-blue-500' : 'bg-teal-500'}`} />
              <div className="flex-1">
                 <h4 className="text-xs font-bold uppercase tracking-wider text-slate-500 mb-1">
                    {groundingResult.source === 'maps' ? 'Google Maps Verification' : 'Google Search Fact Check'}
                 </h4>
                 <p className="text-sm text-slate-700 leading-relaxed mb-2">{groundingResult.data}</p>
                 {groundingResult.uris && groundingResult.uris.length > 0 && (
                     <div className="flex flex-wrap gap-2">
                         {groundingResult.uris.map((u, i) => (
                             <a key={i} href={u.uri} target="_blank" rel="noreferrer" className="text-xs text-blue-600 underline">
                                 {u.title}
                             </a>
                         ))}
                     </div>
                 )}
              </div>
              <button onClick={() => setGroundingResult(null)} className="text-slate-400 hover:text-slate-600">&times;</button>
           </div>
        </div>
      )}

      {/* Tabs */}
      <div className="flex border-b border-slate-200">
        <button
          onClick={() => setActiveTab('refined')}
          className={`flex-1 py-3 text-sm font-medium transition-colors ${activeTab === 'refined' ? 'text-indigo-600 border-b-2 border-indigo-600 bg-indigo-50/50' : 'text-slate-500 hover:text-slate-700'}`}
        >
          Refined Content
        </button>
        <button
          onClick={() => setActiveTab('audit')}
          className={`flex-1 py-3 text-sm font-medium transition-colors ${activeTab === 'audit' ? 'text-indigo-600 border-b-2 border-indigo-600 bg-indigo-50/50' : 'text-slate-500 hover:text-slate-700'}`}
        >
          Audit Log ({data.auditTrail.length})
        </button>
        <button
          onClick={() => setActiveTab('original')}
          className={`flex-1 py-3 text-sm font-medium transition-colors ${activeTab === 'original' ? 'text-indigo-600 border-b-2 border-indigo-600 bg-indigo-50/50' : 'text-slate-500 hover:text-slate-700'}`}
        >
          Original
        </button>
      </div>

      {/* Content */}
      <div className="p-6 overflow-y-auto flex-1">
        {activeTab === 'refined' && (
          <div className="space-y-4">
             {data.operationalAlerts && (
               <div className="bg-slate-50 border border-slate-200 p-4 rounded-lg mb-4">
                 <h4 className="text-xs font-bold text-slate-800 uppercase tracking-widest mb-2 flex items-center gap-2">
                    <svg className="w-4 h-4 text-slate-600" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 16h-1v-4h-1m1-4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
                    Bom saber antes de reservar
                 </h4>
                 <p className="text-sm text-slate-600">{data.operationalAlerts}</p>
               </div>
             )}

             <div className="prose prose-sm max-w-none text-slate-700 whitespace-pre-wrap">
               {data.rewrittenDescription}
             </div>

             <div className="mt-6 pt-4 border-t border-slate-100">
               <span className="text-xs font-semibold text-slate-400 uppercase tracking-wider">SEO Keywords</span>
               <div className="flex flex-wrap gap-2 mt-2">
                 {data.seoKeywords.map((kw, i) => (
                   <span key={i} className="inline-flex items-center px-2.5 py-0.5 rounded-md text-xs font-medium bg-indigo-100 text-indigo-800">
                     {kw}
                   </span>
                 ))}
               </div>
             </div>
          </div>
