import { GoogleGenAI, Type, Schema } from "@google/genai";

// Use specific models as per guidelines
const MODEL_REFINER = "gemini-3-pro-preview"; 
const MODEL_GROUNDING = "gemini-2.5-flash";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const refinerSchema: Schema = {
  type: Type.OBJECT,
  properties: {
    optimizedTitle: { type: Type.STRING, description: "H2 title: Destination + Type + Difference." },
    shortSummary: { type: Type.STRING, description: "One-sentence hook with immediate value proposition." },
    rewrittenDescription: { type: Type.STRING, description: "The core content block in Markdown. Include 'O que esperar' and 'Informações Importantes'. DO NOT include the title here." },
    seoKeywords: { 
      type: Type.ARRAY, 
      items: { type: Type.STRING },
      description: "5-8 natural keywords." 
    },
    operationalAlerts: { type: Type.STRING, description: "Markdown '## Bom saber antes de reservar' section ONLY if risks or intensity are detected." },
    targetAudience: { type: Type.STRING, description: "Mandatory: 'Ideal para: [perfil objective]'." },
    missingInfo: { 
      type: Type.ARRAY, 
      items: { type: Type.STRING },
      description: "Critical missing data: duration, meeting point, inclusions, etc." 
    },
    isReadyForPublication: { type: Type.BOOLEAN, description: "True if all critical data is present. False if info is missing." },
    auditTrail: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          change: { type: Type.STRING, description: "What part changed." },
          reason: { type: Type.STRING, description: "Why it changed." },
          factualConfirmation: { type: Type.STRING, description: "Fact check confirmation." }
        },
        required: ["change", "reason", "factualConfirmation"]
      }
    }
  },
  required: ["optimizedTitle", "shortSummary", "rewrittenDescription", "seoKeywords", "targetAudience", "missingInfo", "isReadyForPublication", "auditTrail"]
};

export const refineProductText = async (originalText: string) => {
  try {
    const response = await ai.models.generateContent({
      model: MODEL_REFINER,
      contents: `
        You are the "iFriend Experience Refiner v2.1", a professional agent transforming raw tourism descriptions for the iFriend platform.

        OBJECTIVE: Generate clear, safe, scannable, and conversion-oriented descriptions with 100% fidelity.

        MANDATORY V2.1 RULES:
        1. **LANGUAGE FIDELITY**: AUTO-DETECT language. Output MUST be in the SAME LANGUAGE as Input.
        2. **STRICT ORDER**: 
           - Title (H2)
           - Hook (Short paragraph)
           - Section "## O que esperar" / "## Sobre esta experiência"
           - Section "### Destaques" (if applicable)
           - Section "### Informações Importantes"
           - Section "## Bom saber antes de reservar" (Triggered by: flights, bikes, long tours +6h, intense physical, weather/altitude/mobility)
           - Line: "**Ideal para:** [profile]"
           - SEO Keywords
        3. **FIDELITY**: NEVER invent duration, logistics, inclusions. NEVER infer unconfirmed data.
        4. **CRITICAL INFO BLOCK**: If duration, meeting point, accessibility, or entry fees are missing, set 'isReadyForPublication' to FALSE and list missing items in 'missingInfo'. If false, the 'rewrittenDescription' should be a minimal draft only.
        5. **FORMAT**: Markdown (H2, H3, bullets). Short sentences. No flowery language.

        Input Text:
        "${originalText}"
      `,
      config: {
        responseMimeType: "application/json",
        responseSchema: refinerSchema,
        temperature: 0.1, 
      }
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI");

    return JSON.parse(text);
  } catch (error) {
    console.error("Refinement Error:", error);
    throw error;
  }
};

export const verifyLocationWithMaps = async (query: string) => {
  try {
    const response = await ai.models.generateContent({
      model: MODEL_GROUNDING,
      contents: `Verify the existence and basic details of this location: ${query}. Respond in the same language as the query.`,
      config: {
        tools: [{ googleMaps: {} }],
      }
    });

    const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
    const uris = chunks?.map((c: any) => ({
      uri: c.maps?.uri || '',
      title: c.maps?.title || 'View on Maps'
    })).filter((u: any) => u.uri) || [];

    return {
      text: response.text || "Location verification not available.",
      uris
    };
  } catch (error) {
    console.error("Maps Error:", error);
    return { text: "Could not verify location at this time.", uris: [] };
  }
};

export const checkFactsWithSearch = async (query: string) => {
  try {
    const response = await ai.models.generateContent({
      model: MODEL_GROUNDING,
      contents: `Fact check this detail: ${query}. Respond in the same language as the query.`,
      config: {
        tools: [{ googleSearch: {} }],
      }
    });

    const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
    const uris = chunks?.map((c: any) => ({
      uri: c.web?.uri || '',
      title: c.web?.title || 'Source'
    })).filter((u: any) => u.uri) || [];

    return {
      text: response.text || "Fact check not available.",
      uris
    };
  } catch (error) {
    console.error("Search Error:", error);
    return { text: "Could not perform search fact check.", uris: [] };
  }
};

